import UIKit

class ViewController: UIViewController {

    let apiServerURL = URL(string: "https://api.example.com/data")!
    let legacyServerURL = URL(string: "http://legacy.internal/status")!

    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
    }

    private func setupUI() {
        view.backgroundColor = .white

        let apiButton = UIButton(type: .system)
        apiButton.setTitle("Call API Server (Secure)", for: .normal)
        apiButton.addTarget(self, action: #selector(callAPIServer), for: .touchUpInside)
        apiButton.translatesAutoresizingMaskIntoConstraints = false

        let legacyButton = UIButton(type: .system)
        legacyButton.setTitle("Call Legacy Server (Insecure)", for: .normal)
        legacyButton.addTarget(self, action: #selector(callLegacyServer), for: .touchUpInside)
        legacyButton.translatesAutoresizingMaskIntoConstraints = false

        let stackView = UIStackView(arrangedSubviews: [apiButton, legacyButton])
        stackView.axis = .vertical
        stackView.spacing = 20
        stackView.translatesAutoresizingMaskIntoConstraints = false

        view.addSubview(stackView)

        NSLayoutConstraint.activate([
            stackView.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            stackView.centerYAnchor.constraint(equalTo: view.centerYAnchor)
        ])
    }

    @objc private func callAPIServer() {
        makeRequest(url: apiServerURL, description: "API Server")
    }

    @objc private func callLegacyServer() {
        makeRequest(url: legacyServerURL, description: "Legacy Server")
    }

    private func makeRequest(url: URL, description: String) {
        print("Making request to \(description): \(url.absoluteString)")

        let task = URLSession.shared.dataTask(with: url) { data, response, error in
            DispatchQueue.main.async {
                if let error = error {
                    print("Error calling \(description): \(error.localizedDescription)")
                    self.showAlert(title: "Error", message: "Failed to call \(description): \(error.localizedDescription)")
                    return
                }

                if let httpResponse = response as? HTTPURLResponse {
                    print("Status code for \(description): \(httpResponse.statusCode)")
                    if httpResponse.statusCode >= 200 && httpResponse.statusCode < 300 {
                        if let data = data, let dataString = String(data: data, encoding: .utf8) {
                            print("Response from \(description): \(dataString)")
                            self.showAlert(title: "Success", message: "Successfully called \(description).\nStatus: \(httpResponse.statusCode)\nData: \(dataString.prefix(100))...")
                        } else {
                            print("No data or couldn't decode data for \(description).")
                            self.showAlert(title: "Success (No Data)", message: "Successfully called \(description).\nStatus: \(httpResponse.statusCode)\nNo data returned.")
                        }
                    } else {
                        print("Non-2xx status code for \(description): \(httpResponse.statusCode)")
                        self.showAlert(title: "Failed", message: "Failed to call \(description).\nStatus: \(httpResponse.statusCode)")
                    }
                } else {
                    print("No HTTP response for \(description).")
                    self.showAlert(title: "Error", message: "No HTTP response received from \(description).")
                }
            }
        }
        task.resume()
    }

    private func showAlert(title: String, message: String) {
        let alert = UIAlertController(title: title, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default, handler: nil))
        present(alert, animated: true, completion: nil)
    }
}

